          MaskVal = OldConstC;
          TheMask = ConstB;
          MaskedICmp = cast<ICmpInst>(LHS);
        }
        if (ExactC && *ExactC + 1 == *MaskVal) {
          APInt NotMask = ~(*TheMask);
          APInt RangeSize = NotMask + 1; // 2^K
