          APInt RangeSize = NotMask + 1; // 2^K
          if (RangeSize.isPowerOf2() && RangeSize.ugt(1) &&
              (*MaskVal & NotMask) == 0) {
            // If the masked icmp's operand is an 'and' with more than one
            // use, we can't replace it without keeping the 'and' instruction.
            bool HasMultiUseAnd = false;
            for (Value *Op : {MaskedICmp->getOperand(0),
                              MaskedICmp->getOperand(1)}) {
              if (auto *I = dyn_cast<BinaryOperator>(Op))
                if (I->getOpcode() == Instruction::And &&
                    I->getNumUses() > 1)
                  HasMultiUseAnd = true;
            }
            if (!HasMultiUseAnd) {
              APInt RangeLimit = RangeSize + 1; // 2^K + 1
              Value *Sub = Builder.CreateAdd(
                  A, ConstantInt::get(A->getType(), -(*ExactC)));
              return Builder.CreateICmp(ICmpInst::ICMP_ULT, Sub,
                  ConstantInt::get(A->getType(), RangeLimit));
            }
          }
        }
      }

      auto FoldBMixed = [&](ICmpInst::Predicate CC, bool IsNot) -> Value * {
        CC = IsNot ? CmpInst::getInversePredicate(CC) : CC;
        const APInt ConstC = PredL != CC ? *ConstB ^ *OldConstC : *OldConstC;
        const APInt ConstE = PredR != CC ? *ConstD ^ *OldConstE : *OldConstE;

        if (((*ConstB & *ConstD) & (ConstC ^ ConstE)).getBoolValue())
          return IsNot ? nullptr : ConstantInt::get(LHS->getType(), !IsAnd);

        if (IsNot && !ConstB->isSubsetOf(*ConstD) &&
            !ConstD->isSubsetOf(*ConstB))
          return nullptr;

        APInt BD, CE;
        if (IsNot) {
          BD = *ConstB & *ConstD;
          CE = ConstC & ConstE;
        } else {
          BD = *ConstB | *ConstD;
          CE = ConstC | ConstE;
        }
        Value *NewAnd = Builder.CreateAnd(A, BD);
        Value *CEVal = ConstantInt::get(A->getType(), CE);
        return Builder.CreateICmp(CC, NewAnd, CEVal);
      };

      if (Mask & BMask_Mixed)
        return FoldBMixed(NewCC, false);
      if (Mask & BMask_NotMixed) // can be else also
        return FoldBMixed(NewCC, true);
CODEEOF"}

